import { Pool, Client } from 'pg';
import express, { Request, Response } from 'express';

const pool = new Pool({
  host: 'localhost',
  port: 5432,
  database: 'myapp',
  user: 'postgres',
  password: 'password'
});

const app = express();
app.use(express.json());

interface SearchParams {
  name?: string;
  email?: string;
  role?: string;
  status?: string;
  age?: string;
  department?: string;
  minSalary?: string;
  maxSalary?: string;
  orderBy?: string;
  orderDir?: string;
}

function buildWhereConditions(params: SearchParams): string {
  const conditions: string[] = [];

  if (params.name) {
    conditions.push(`name LIKE '%${params.name}%'`);
  }

  if (params.email) {
    conditions.push(`email = '${params.email}'`);
  }

  if (params.role) {
    conditions.push(`role = '${params.role}'`);
  }

  if (params.status) {
    conditions.push(`status = '${params.status}'`);
  }

  if (params.age) {
    conditions.push(`age = ${params.age}`);
  }

  if (params.department) {
    conditions.push(`department = '${params.department}'`);
  }

  if (params.minSalary) {
    conditions.push(`salary >= ${params.minSalary}`);
  }

  if (params.maxSalary) {
    conditions.push(`salary <= ${params.maxSalary}`);
  }

  return conditions.length > 0 ? conditions.join(' AND ') : '1=1';
}

app.get('/api/users/search', async (req: Request, res: Response) => {
  try {
    const params: SearchParams = req.query;
    const conditions = buildWhereConditions(params);
    
    let query = `SELECT * FROM users WHERE ${conditions}`;

    if (params.orderBy) {
      const orderDir = params.orderDir || 'ASC';
      query += ` ORDER BY ${params.orderBy} ${orderDir}`;
    }

    const client = await pool.connect();
    const result = await client.query(query);
    client.release();

    res.json({
      success: true,
      count: result.rows.length,
      data: result.rows
    });
  } catch (error: any) {
    res.status(500).json({
      success: false,
      error: error.message
    });
  }
});

